vector<long long> maximumEvenSplit(long long finalSum) {
    if (finalSum % 2 != 0) return {};
    long long sum = 0, count = 0;
    for (long long i = 2; i <= finalSum; i += 2) {
        if (sum + i > finalSum) break;
        sum += i;
        count++;
    }
    vector<long long> res;
    for (long long i = 2; i <= finalSum; i += 2) {
        if (sum <= finalSum) {
            res.push_back(i);
            sum -= i;
        } else break;
    }
    return res;
}
```
